+		return errors.New("empty response")
+	}
+	defer resp.Body.Close()
+
+	var r io.Reader = resp.Body
+	if c.MaxBytes > 0 {
+		r = io.LimitReader(resp.Body, c.MaxBytes)
+	}
+	b, err := io.ReadAll(r)
+	if err != nil {
+		return err
+	}
