+	if err != nil {
+		return err
+	}
+
+	if ctx != nil {
+		kctx.BindTo(ctx, (*context.Context)(nil))
+	}
+	if flags != nil {
+		kctx.Bind(flags)
+	}
+
+	return kctx.Run()
+}

